import type { WarehouseDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import type { WarehouseTypeValue } from './warehouseTypeOptions';

export function toCreateWarehousePayload(form: Partial<WarehouseDto>) {
  return {
    code: normalizeCode(form.code ?? ''),
    name: form.name!.trim(),
    location: form.location?.trim() || undefined,
    warehouseType: form.warehouseType as WarehouseTypeValue,
  };
}

export function toUpdateWarehousePayload(form: Partial<WarehouseDto>) {
  return {
    name: form.name!.trim(),
    location: form.location?.trim() || undefined,
    warehouseType: form.warehouseType as WarehouseTypeValue,
    isActive: form.isActive ?? true,
  };
}
